import{_ as e,c as p,o as t,ae as o}from"./chunks/framework.BvcDoAct.js";const s=JSON.parse('{"title":"TAKUTO (MAZZEL)","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/17_TAKUTO.md","filePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/17_TAKUTO.md"}'),r={name:"zh-cn/Management2Extra/01_TalkAboutBMSG/17_TAKUTO.md"};function n(l,a,i,S,T,A){return t(),p("div",null,[...a[0]||(a[0]=[o('<p>Talk about BMSG - 17</p><h1 id="takuto-mazzel" tabindex="-1">TAKUTO (MAZZEL) <a class="header-anchor" href="#takuto-mazzel" aria-label="Permalink to &quot;TAKUTO (MAZZEL)&quot;">​</a></h1><h3 id="谢谢你选择了我们公司-——让我感受到他不是居高临下-而是以平等的立场对待我们" tabindex="-1">“谢谢你选择了我们公司”——让我感受到他不是居高临下，而是以平等的立场对待我们 <a class="header-anchor" href="#谢谢你选择了我们公司-——让我感受到他不是居高临下-而是以平等的立场对待我们" aria-label="Permalink to &quot;“谢谢你选择了我们公司”——让我感受到他不是居高临下，而是以平等的立场对待我们&quot;">​</a></h3><p><em>TAKUTO：1998年10月28日出生，东京都出身</em></p><p>————TAKUTO，你在与SKY-HI相遇、一路一起切磋成长的过程中，有没有什么让你印象特别深刻的事情？</p><p>可能是我有点先入为主的印象吧，我原本觉得如果是事务所社长来做选秀的话，应该会在评审时给出比较严厉的评价……但在《MISSIONx2》的时候，社长对我们说话的方式真的让我非常感动。他会反复对我们说“谢谢你们的努力”“谢谢你选择了我们公司”，完全不是高高在上的感觉，而是以一种平等的立场来对待我们。从《MISSIONx2》到现在，这种印象一直都没有改变。因为社长对任何人都会表达尊重，所以也让我更坚定了“我一定要加入这里”的想法。而且在BMSG里，一直都让我感到很舒适。</p><h3 id="mazzel惯例-在社长家进行-烤肉便当会议" tabindex="-1">MAZZEL惯例：在社长家进行“烤肉便当会议” <a class="header-anchor" href="#mazzel惯例-在社长家进行-烤肉便当会议" aria-label="Permalink to &quot;MAZZEL惯例：在社长家进行“烤肉便当会议”&quot;">​</a></h3><p>————TAKUTO，你是被SKY-HI直接任命为MAZZEL的队长的吧。有没有从他身上学到一些关于“领导者”的东西？</p><p>是的。他也把这样的期望托付给我：“因为不可能每天都在一起，希望你能成为一个可以把我（SKY-HI）的想法好好传达给成员的人。”成为队长之后，我的责任感也更强了，同时也更加觉得，社长的思考方式有很多值得我去学习的地方。我一直在思考“怎样才能让MAZZEL的8个人朝着更好的方向前进”，不断地尝试和摸索。有机会和社长单独交流的时候，我也会向他请教，比如“这种时候你觉得该怎么做比较好？”之类的问题。毕竟向像社长这样的人请教，我觉得是最直接的捷径。我也希望一边听、一边学，作为队长不断成长。</p><p>————听说2024年你们和SKY-HI一起相处的时间更多了，这种关系上有没有什么变化？</p><p>是的。我们8个人去社长家做客的次数也变多了。其实从出道前开始就一直是这样——大家先一起吃烤肉便当，然后再聊天……已经成了固定流程（笑）。一开始是很轻松地聊天，但常常不知不觉就变成了很认真的话题。</p><p>————2024年你们经历了首次全国巡演和首次单独Arena公演。看了现场之后，能明显感受到作为团队的巨大成长，这种成长的原因你觉得在哪里？</p><p>说实话，究竟是什么带来了成长，我们自己也有很多说不清的地方。在“BMSG FES&#39;24”结束后，我们和社长一起去吃饭，他给了我们关于演出的反馈。关于Arena公演，他对我们说：“不安和紧张当然都会有，但把这些全部变成自己的助力，用一种‘我们是Arena级艺人’的姿态，堂堂正正地去演就好了。”也正因为这样，我们才能以非常自信的状态去完成表演。</p><p>————那你们自己有没有感觉到，在巡演过程中是以很快的速度在成长？</p><p>通过这9场巡演，我们是一场一场踏实地积累过来的。巡演的场地不只有Hall，也有Live House。社长当时也说过：“在这个阶段先经历Live House，再走到Arena，一定是很好的流程。”等真的站上舞台后，我也觉得“确实如此”。因为先体验过不同场地与观众之间完全不同的距离感，之后再站上Arena，等回头看录像时，就能明显感受到“我们在一点点成长”。虽然很难用语言具体说明，可能是气场、也可能是从容度之类的东西吧。相比“害怕Arena”，我们是抱着“放马过来、我们要上了”的心态站上去的，这也是因为我们把整个巡演都认真完成了。</p><h3 id="拥有打动人心力量的社长的语言感" tabindex="-1">拥有打动人心力量的社长的语言感 <a class="header-anchor" href="#拥有打动人心力量的社长的语言感" aria-label="Permalink to &quot;拥有打动人心力量的社长的语言感&quot;">​</a></h3><p>————请再说说，你特别尊敬SKY-HI的哪些方面？</p><p>有很多，而且和一开始说的有点重复，但我还是非常憧憬社长的“用词与表达能力”。每次听他说话，都会觉得“好厉害”“说得真好”。无论是现场演出的MC，还是接受采访时的发言都是如此。我经常会想“社长当时是这么说的，那我也试着这样去努力”，所以我觉得他真的是一个非常有能力打动人心的人。</p><p>————不仅词汇丰富，而且他那种能够直击人心的表达方式也很厉害，对吧？</p><p>完全是这样。我自己在这方面还完全做不到，所以总是觉得他很厉害。另外，有时候社长会用一些我们不太懂的词，我也会忍不住装作自己听懂了（笑）。</p><p>————（笑）那也请说说现在整个BMSG的氛围吧。本社大楼建成之后，你在公司内部的交流有没有发生什么变化？</p><p>现在所属艺人大概有23人，要说和所有人都非常熟的话，其实还是会因人而异、存在距离感。不过只要去公司，在桑拿或者艺人休息室基本一定会遇到人，所以聊天的机会确实变多了，也会发现“原来这个人是这样的性格”，从而慢慢变得更亲近。</p><p>特别是我在桑拿里加深了交流的是edhiii boi，感觉他比我原本想象的还要更好相处（笑）。而且摆着沙发和游戏机的艺人休息室，位置上也能和在桑拿里的人聊天，这种交流方式也挺有意思的。我觉得社长是想打造一个大家可以轻松聚在一起交流的空间，而这个想法确实已经实现了。自从有了这栋大楼之后，也更能感受到彼此之间的距离变近了。</p><p>————在“BMSG FES&#39;24”中，你获得了怎样的刺激？</p><p>MAZZEL成员各自的表演方式，我已经非常熟悉了，但和BE:FIRST或者solo艺人其实很少有一起演出的机会。所以在现场看到他们，比如“原来这种时候可以用这样的方式去带动气氛”，能看到和我们不同的地方，也会有很多“原来如此”的新发现。</p><p>————通过“BMSG FES”，你也再次感受到BMSG的魅力。那作为其中一员，你觉得它的强项和你引以为傲的地方是什么？</p><p>我觉得最大的强项还是——社长是SKY-HI这一点。如果有想做的事情，可以很坦率地表达出来，而且社长也会说“很好啊，那就去做吧！”这样的关系真的很珍贵。公司一直很重视“Be My Self”，而我也确实每天都能以“做自己”的状态去活动，这一点让我觉得“能在BMSG真是太好了”。</p><p>————2025年，继BE:FIRST、MAZZEL之后，第三支男子团体将通过选秀《THE LAST PIECE》诞生。你现在有什么样的想法？</p><p>第一次在“BMSG FES”看到RUI、TAIKI、KANON表演《Forked Road》的时候，我真的很感动，对我来说冲击也很大。也会想起当初在《MISSIONx2》和KANON一起度过的日子，各种情绪都涌上来。与其说是不想输，不如说是“我们一起加油吧！”这样的心情。能有更多一起挑战各种事情的伙伴，我觉得很开心，从现在就非常期待了。</p><blockquote><h3 id="from-sky-hi" tabindex="-1">from SKY-HI <a class="header-anchor" href="#from-sky-hi" aria-label="Permalink to &quot;from SKY-HI&quot;">​</a></h3><p>从他还是舞者的时候起，我就觉得“这个人跳舞很有艺人的感觉”，而现在他已经彻底蜕变成了一位舞技出众的艺人。</p><p>其实现在我最想多给舞台经验的也是TAKUTO。他的潜力，在一年之内还能再“进化”两三次。</p><p>我也很期待那一天的到来——让人觉得“任命他为队长果然是正确的”。到那时，他一定会展现出一种谁看了都能一眼看出来的领袖气质。敬请期待吧。</p></blockquote>',30)])])}const d=e(r,[["render",n]]);export{s as __pageData,d as default};
